/* Professional styling optimized for ATS and visual impact */

.section h3 {
  font-weight: bold;
  font-size: 14px;
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 8px;
  color: #1e40af;
  border-bottom: 1px solid #e5e7eb;
  padding-bottom: 4px;
}

.experience-item h4 {
  font-weight: bold;
  font-size: 12px;
  color: #111827;
}

.experience-item .company {
  font-weight: 600;
  color: #374151;
}

.experience-item .position {
  font-style: italic;
  color: #6b7280;
}

/* Enhanced bullet styling for impact */
ul li {
  margin-bottom: 6px;
  line-height: 1.4;
}

ul li strong {
  color: #1e40af;
  font-weight: 600;
}

/* Professional section spacing */
.section {
  margin-bottom: 18px;
}

/* Clean typography for ATS and human reading */
body {
  font-family: 'Arial', 'Calibri', 'Helvetica', sans-serif;
  font-size: 11px;
  line-height: 1.35;
  color: #374151;
}

/* Highlight achievements and metrics */
.achievement-item {
  margin-bottom: 12px;
}

.achievement-item h4 {
  color: #1e40af;
  font-weight: 600;
  margin-bottom: 4px;
}

/* Project styling */
.project-item {
  margin-bottom: 14px;
}

.project-item h4 {
  color: #059669;
  font-weight: 600;
}

/* Skills section optimization */
.skills-item {
  margin-bottom: 10px;
}

.skills-item h4 {
  color: #7c3aed;
  font-weight: 600;
  margin-bottom: 3px;
}

/* Contact information styling */
.contact-item {
  margin-bottom: 2px;
  font-size: 10px;
}

/* Print optimization */
@media print {
  .section {
    break-inside: avoid;
  }

  body {
    font-size: 10px;
  }
}
